const fs = require('fs');
const path = require('path');
const dir = path.join(__dirname, '..', 'lessons');

// Helper to create a lesson
function L(title, sub, xp, content, q, o, c, exp) {
  return { title, sub, xp, content, quiz: { q, o, c, exp } };
}

// MOD 62: Resiliência e Autoconhecimento
const mod62 = {
  title: "Resiliência e Autoconhecimento",
  icon: "💡", desc: "Desenvolva força interior, autoconhecimento e habilidades emocionais para a vida.",
  color: "honey", discipline: "emocional",
  lessons: [
    L("O que é Resiliência?", "A força de se levantar após cada queda", 30,
      '<h3>O que é Resiliência?</h3><p>Resiliência é a capacidade de <strong>enfrentar adversidades, adaptar-se e sair mais forte</strong>. Não é sobre nunca cair — é sobre sempre se levantar.</p><p>A palavra vem da física: materiais resilientes são aqueles que, após serem deformados, voltam à forma original. Na psicologia, significa a capacidade humana de se recuperar de traumas, perdas e dificuldades.</p><div class="highlight">💪 Resiliência NÃO é: nunca sentir dor, ignorar problemas, ser insensível. Resiliência É: sentir a dor, processá-la e encontrar forças para continuar.</div><h3>A Ciência da Resiliência</h3><p>Pesquisas mostram que resiliência não é um traço fixo — é uma <strong>habilidade que pode ser desenvolvida</strong>. Fatores que aumentam resiliência:</p><p>• <strong>Relações de apoio</strong> — ter pelo menos uma pessoa de confiança<br>• <strong>Senso de propósito</strong> — saber por que você faz o que faz<br>• <strong>Autoeficácia</strong> — acreditar que suas ações fazem diferença<br>• <strong>Regulação emocional</strong> — gerenciar emoções sem ser dominado por elas</p><div class="example">🏋️ Viktor Frankl sobreviveu a campos de concentração nazistas e depois escreveu "Em Busca de Sentido". Sua conclusão: quem tinha um propósito forte sobrevivia; quem não tinha, desistia. "Quem tem um porquê vive qualquer como."</div><h3>Resiliência no Dia a Dia</h3><p>Você não precisa passar por tragédias para exercitar resiliência. Cada prova difícil, cada amizade perdida, cada fracasso é uma oportunidade de praticar. A chave é: <strong>o que acontece com você importa menos do que como você responde.</strong></p><div class="thinker-quote">"A vida não é o que acontece com você, mas o que você faz com o que acontece." — Epicteto</div>',
      "O que define uma pessoa resiliente?",
      ["Nunca sentir dor ou tristeza", "Capacidade de se recuperar e crescer após adversidades", "Ignorar os problemas", "Ser insensível às emoções"], 1,
      "Resiliência não é ausência de sofrimento, mas a capacidade de enfrentar adversidades, aprender com elas e sair mais forte."),

    L("Autoconhecimento", "O mapa das suas emoções e padrões", 30,
      '<h3>Conhece-te a Ti Mesmo</h3><p>Essa frase estava inscrita no Templo de Apolo em Delfos, na Grécia Antiga. Sócrates a adotou como princípio central de sua filosofia. Dois milênios depois, a ciência confirma: <strong>autoconhecimento é a base de toda inteligência emocional</strong>.</p><p>Autoconhecimento significa entender suas emoções, gatilhos, padrões de comportamento, valores e crenças. Quem se conhece toma melhores decisões, tem relacionamentos mais saudáveis e sofre menos com ansiedade.</p><h3>O Diário de Emoções</h3><p>Uma das ferramentas mais poderosas de autoconhecimento é o <strong>diário de emoções</strong>:</p><p>1. <strong>Situação</strong> — O que aconteceu?<br>2. <strong>Emoção</strong> — O que senti? (raiva, medo, tristeza, alegria?)<br>3. <strong>Intensidade</strong> — De 1 a 10, quão forte?<br>4. <strong>Pensamento</strong> — O que pensei na hora?<br>5. <strong>Padrão</strong> — Isso já aconteceu antes?</p><div class="example">📓 Exemplo: "Fiquei com raiva (8/10) quando meu amigo cancelou planos. Pensei: ele não se importa comigo. Padrão: sempre reajo assim a cancelamentos. Talvez eu esteja interpretando como rejeição pessoal algo que não é."</div><div class="highlight">🔍 O primeiro passo para mudar é perceber. Você não pode gerenciar emoções que não reconhece. Auto-observação sem julgamento é a chave.</div><h3>Cuidado com o Autoengano</h3><p>Nosso cérebro é especialista em nos enganar. Temos "pontos cegos" — coisas sobre nós que todos veem, menos nós mesmos. Por isso, feedback honesto de pessoas de confiança é valioso.</p><div class="thinker-quote">"A vida não examinada não vale a pena ser vivida." — Sócrates</div>',
      "Qual é o primeiro passo para o autoconhecimento?",
      ["Pedir opinião dos outros", "Observar suas próprias emoções e reações sem julgamento", "Ler muitos livros", "Meditar 3 horas por dia"], 1,
      "O autoconhecimento começa com auto-observação: notar suas emoções, gatilhos e padrões de comportamento sem julgá-los."),

    L("Lidando com Fracassos", "O fracasso como professor, não como destino", 30,
      '<h3>Fracasso: Inimigo ou Professor?</h3><p>Todo mundo fracassa. A diferença entre pessoas que crescem e pessoas que estagnam não é a ausência de fracassos — é <strong>como interpretam e respondem a eles</strong>.</p><h3>Mentalidade Fixa vs Crescimento</h3><p>Carol Dweck, psicóloga de Stanford, descobriu duas mentalidades fundamentais:</p><p><strong>Mentalidade fixa:</strong> "Falhei porque sou burro. Inteligência é algo que se nasce com ou sem."<br><strong>Mentalidade de crescimento:</strong> "Falhei porque ainda não aprendi. Com esforço e estratégia, posso melhorar."</p><div class="highlight">🧠 Seu cérebro é como um músculo — ele se fortalece com uso. Neuroplasticidade: cada vez que você aprende algo novo ou supera um desafio, seu cérebro literalmente cria novas conexões.</div><div class="example">💡 Thomas Edison falhou milhares de vezes antes de inventar a lâmpada. Quando perguntado sobre os fracassos, disse: "Eu não falhei. Apenas descobri 10.000 maneiras que não funcionam." J.K. Rowling foi rejeitada por 12 editoras antes de Harry Potter ser publicado.</div><h3>O Método Anti-Fracasso</h3><p>Quando fracassar, pergunte-se:<br>1. <strong>O que aconteceu?</strong> (fatos, não emoções)<br>2. <strong>O que eu aprendi?</strong><br>3. <strong>O que farei diferente?</strong></p><p>Isso transforma fracasso em feedback construtivo.</p><div class="thinker-quote">"Sucesso é ir de fracasso em fracasso sem perder o entusiasmo." — Winston Churchill</div>',
      "Na mentalidade de crescimento, o fracasso é visto como:",
      ["Prova de incapacidade", "Oportunidade de aprendizado", "Algo a ser evitado sempre", "Culpa dos outros"], 1,
      "Na mentalidade de crescimento (Carol Dweck), fracassos são oportunidades de aprendizado, não provas de limitação."),

    L("Inteligência Social", "A arte de entender e conectar com pessoas", 30,
      '<h3>Além do QI: Inteligência Social</h3><p>Inteligência social é a capacidade de <strong>entender dinâmicas sociais, ler emoções dos outros e construir relações saudáveis</strong>. Pesquisas mostram que ela é mais importante que o QI para o sucesso na vida.</p><h3>Os 5 Pilares</h3><p><strong>1. Leitura emocional</strong> — Identificar o que os outros sentem pela expressão facial, tom de voz e linguagem corporal.<br><strong>2. Escuta ativa</strong> — Ouvir para entender, não para responder.<br><strong>3. Adaptabilidade</strong> — Ajustar seu comportamento ao contexto.<br><strong>4. Influência positiva</strong> — Inspirar sem manipular.<br><strong>5. Resolução de conflitos</strong> — Transformar desentendimentos em soluções.</p><div class="example">👥 Em entrevistas de emprego, 85% da decisão é baseada em soft skills (comunicação, empatia, trabalho em equipe) e apenas 15% em conhecimento técnico. A pessoa mais inteligente nem sempre é a escolhida — é a que melhor se conecta.</div><div class="highlight">🎯 Dica prática: antes de responder em qualquer conversa, respire e pergunte-se: "O que essa pessoa está realmente precisando agora?" Muitas vezes, não é conselho — é ser ouvida.</div><div class="thinker-quote">"As pessoas podem esquecer o que você disse, mas nunca esquecerão como você as fez sentir." — Maya Angelou</div>',
      "O que é inteligência social?",
      ["Ter muitos seguidores nas redes sociais", "Capacidade de entender e navegar relações interpessoais", "Ser popular na escola", "Saber manipular pessoas"], 1,
      "Inteligência social é a habilidade de compreender dinâmicas sociais, ler emoções dos outros e construir relações saudáveis."),

    L("Gerenciando a Raiva", "Técnicas para transformar raiva em ação construtiva", 30,
      '<h3>Raiva: Emoção Poderosa</h3><p>Raiva não é ruim. É uma emoção natural que sinaliza que algo está errado — seus limites foram violados, algo é injusto, ou você se sente ameaçado. O problema não é sentir raiva, é <strong>o que você faz com ela</strong>.</p><h3>O Que Acontece no Cérebro</h3><p>Quando você sente raiva intensa, a <strong>amígdala</strong> (centro emocional) sequestra seu cérebro. O cortisol e adrenalina inundam seu corpo. Seu coração acelera, músculos tensionam, pensamento racional diminui. É o modo "luta ou fuga".</p><div class="highlight">⏱️ A boa notícia: esse sequestro emocional dura apenas 90 segundos se você não alimentá-lo com pensamentos ruminantes. Respire fundo por 90 segundos e o pior passa.</div><h3>Técnica PARAR</h3><p><strong>P</strong>are — congele antes de reagir<br><strong>A</strong>respire — 3 respirações profundas<br><strong>R</strong>econheça — "estou com raiva porque..."<br><strong>A</strong>valie — "o que é mais inteligente fazer agora?"<br><strong>R</strong>esponda — aja com intenção, não impulso</p><div class="example">😤 Cenário: alguém te insulta no grupo. Impulso: xingar de volta. PARAR: respire, reconheça a raiva, avalie (xingar vai piorar), responda (ignorar ou responder com calma depois). Resultado: você mantém o controle.</div><div class="thinker-quote">"Qualquer um pode ficar com raiva — isso é fácil. Mas ficar com raiva da pessoa certa, na medida certa, na hora certa, pelo motivo certo — isso não é fácil." — Aristóteles</div>',
      "Qual técnica ajuda a controlar a raiva no momento?",
      ["Gritar para liberar", "Respiração profunda e pausa antes de reagir", "Ignorar completamente", "Culpar alguém"], 1,
      "A pausa e respiração profunda ativa o sistema parassimpático, desacelera o coração e permite que o cérebro racional retome o controle."),

    L("Ansiedade e Como Enfrentar", "Entendendo e dominando a ansiedade", 30,
      '<h3>Ansiedade: Alarme do Corpo</h3><p>Ansiedade é o sistema de alarme do seu corpo. Ela surgiu para nos proteger de predadores e perigos. O problema é que nosso cérebro de 200 mil anos não distingue bem entre um leão e uma prova de matemática — <strong>ativa o mesmo alarme para ambos</strong>.</p><h3>Ansiedade Normal vs Problemática</h3><p><strong>Normal:</strong> Ficar nervoso antes de uma apresentação. Motivação leve que te faz preparar melhor.<br><strong>Problemática:</strong> Não conseguir dormir semanas antes da apresentação. Evitar situações. Sintomas físicos constantes.</p><div class="highlight">📊 Ansiedade é o transtorno mental mais comum no mundo. No Brasil, atinge ~19 milhões de pessoas. Não é fraqueza — é uma condição que pode ser tratada e gerenciada.</div><h3>Técnicas Baseadas em Evidência</h3><p><strong>1. Respiração 4-7-8:</strong> Inspire por 4 segundos, segure por 7, expire por 8. Repita 3 vezes. Isso ativa o sistema nervoso parassimpático (modo calma).</p><p><strong>2. Grounding 5-4-3-2-1:</strong> Nomeie 5 coisas que vê, 4 que toca, 3 que ouve, 2 que cheira, 1 que sente gosto. Isso te traz ao presente.</p><p><strong>3. Reestruturação cognitiva:</strong> "E se eu falhar?" → "E se eu conseguir? E se falhar, o que realmente acontece? Morro? Não. Aprendo."</p><div class="example">🧘 Atletas de elite usam técnicas de gerenciamento de ansiedade. Simone Biles fala abertamente sobre ansiedade. Michael Phelps pratica visualização. A ansiedade não é inimiga — é energia que pode ser redirecionada.</div><div class="thinker-quote">"A coragem não é a ausência de medo, mas o julgamento de que algo é mais importante do que o medo." — Ambrose Redmoon</div>',
      "Ansiedade em nível moderado pode ser:",
      ["Sempre prejudicial", "Útil como sinal de alerta e motivação", "Um sinal de fraqueza", "Impossível de controlar"], 1,
      "Ansiedade moderada é uma resposta natural que nos alerta para perigos e nos motiva a agir. Só é problema quando crônica."),

    L("Autoestima Saudável", "A diferença entre se valorizar e se inflar", 30,
      '<h3>Autoestima: O que Realmente É</h3><p>Autoestima saudável não é achar que você é incrível em tudo. É <strong>reconhecer seu valor como pessoa enquanto aceita suas limitações</strong>. É dizer: "Tenho qualidades e defeitos. Mereço respeito — de mim mesmo e dos outros."</p><h3>Autoestima vs Narcisismo</h3><p><strong>Autoestima saudável:</strong> "Sou bom em matemática, mas preciso melhorar em comunicação. Tudo bem — sou um trabalho em andamento."<br><strong>Narcisismo:</strong> "Sou o melhor em tudo. Quem discorda está com inveja. Nunca erro."</p><div class="highlight">⚖️ A diferença crucial: autoestima saudável é estável e tolerante a críticas. Narcisismo é frágil — qualquer crítica provoca reação defensiva ou agressiva, porque a pessoa precisa manter a ilusão de perfeição.</div><h3>Como Construir Autoestima Saudável</h3><p><strong>1. Competência real</strong> — Desenvolva habilidades genuínas. Nada constrói mais autoestima do que fazer algo difícil e conseguir.</p><p><strong>2. Autocompaixão</strong> — Trate-se como trataria um amigo que errou. Autocrítica destrutiva não motiva — paralisa.</p><p><strong>3. Valores internos</strong> — Baseie seu valor em quem você é e no que faz, não em likes, aprovação ou posses.</p><div class="example">📱 Redes sociais destroem autoestima porque nos fazem comparar nosso "bastidor" com o "palco" dos outros. Ninguém posta os fracassos. A comparação com versões editadas da realidade é tóxica.</div><div class="thinker-quote">"Ninguém pode fazer você se sentir inferior sem o seu consentimento." — Eleanor Roosevelt</div>',
      "Qual a diferença entre autoestima saudável e narcisismo?",
      ["Não há diferença", "Autoestima reconhece falhas; narcisismo nega qualquer imperfeição", "Narcisismo é sempre melhor", "Autoestima é para fracos"], 1,
      "Autoestima saudável inclui reconhecer qualidades e defeitos. Narcisismo é uma visão inflada e frágil de si mesmo."),

    L("Tomada de Decisão Emocional", "Como emoções afetam (e podem melhorar) suas escolhas", 30,
      '<h3>Emoções e Decisões</h3><p>Você já fez uma compra por impulso e se arrependeu? Disse algo com raiva que gostaria de voltar atrás? Essas são decisões emocionais — e todos nós as tomamos.</p><h3>O Cérebro Duplo</h3><p>Daniel Kahneman (Nobel de Economia) descreveu dois sistemas de pensamento:</p><p><strong>Sistema 1:</strong> Rápido, automático, emocional. É ele que decide quando você está com fome, medo ou raiva. Responde em milissegundos.</p><p><strong>Sistema 2:</strong> Lento, deliberado, racional. É ele que calcula, planeja e pondera prós e contras. Requer esforço consciente.</p><div class="highlight">🧠 Sob emoção intensa, o Sistema 1 domina e o Sistema 2 "desliga". Por isso decisões tomadas com raiva, medo ou euforia tendem a ser piores — falta a parte racional da equação.</div><h3>A Regra das 24 Horas</h3><p>Para decisões importantes, aplique a <strong>regra das 24 horas</strong>: espere um dia antes de agir. Isso permite que o Sistema 2 recupere o controle.</p><div class="example">💰 Antes de comprar algo caro por impulso: coloque no carrinho e espere 24h. Em 80% dos casos, você percebe que não precisava. As lojas sabem disso — por isso criam "ofertas por tempo limitado" para forçar decisão emocional.</div><h3>Emoções Como Dados</h3><p>Emoções não são inimigas das boas decisões — são <strong>dados importantes</strong>. O medo pode sinalizar um risco real. A empolgação pode indicar uma oportunidade. A chave é: use emoções como informação, não como comando.</p><div class="thinker-quote">"Entre o estímulo e a resposta, há um espaço. Nesse espaço está nosso poder de escolha." — Viktor Frankl</div>',
      "Por que decisões tomadas sob forte emoção tendem a ser piores?",
      ["Emoções sempre atrapalham", "O córtex pré-frontal (raciocínio) fica menos ativo sob emoção intensa", "Decisões emocionais são sempre melhores", "Não há relação entre emoção e decisão"], 1,
      "Sob emoção intensa, a amígdala domina e o córtex pré-frontal fica menos ativo, prejudicando decisões racionais."),

    L("Empatia Avançada", "Além de sentir — compreender perspectivas", 30,
      '<h3>Empatia: A Habilidade do Século XXI</h3><p>Empatia é a capacidade de <strong>se colocar no lugar do outro e compreender sua perspectiva</strong>. Não é concordar, não é sentir pena — é entender genuinamente como o outro vê o mundo.</p><h3>Três Tipos de Empatia</h3><p><strong>1. Empatia cognitiva</strong> — Entender o que o outro pensa e por quê. "Consigo ver seu ponto de vista."<br><strong>2. Empatia emocional</strong> — Sentir o que o outro sente. "Sinto sua dor."<br><strong>3. Empatia compassiva</strong> — Entender + sentir + agir para ajudar. "Vou fazer algo sobre isso."</p><div class="highlight">💡 Empatia ≠ simpatia. Simpatia é "coitado de você" (distância). Empatia é "eu entendo como é" (conexão). Brené Brown: "Empatia é sentir COM as pessoas. Simpatia é sentir PELAS pessoas."</div><h3>Perspective Taking</h3><p>A técnica mais poderosa de empatia avançada é o <strong>perspective taking</strong> (tomada de perspectiva): conscientemente imaginar o mundo através dos olhos do outro.</p><div class="example">🎭 Antes de julgar alguém, pergunte: "Se eu tivesse crescido onde essa pessoa cresceu, com as experiências que ela teve, com as informações que ela tem — eu pensaria diferente?" Quase sempre a resposta é sim.</div><h3>Empatia e Conflitos</h3><p>A maioria dos conflitos não é entre "certo e errado" — é entre duas perspectivas legítimas. Quando você pratica empatia num conflito, não está "perdendo" — está ganhando informação para encontrar soluções melhores.</p><div class="thinker-quote">"Busque primeiro compreender, depois ser compreendido." — Stephen Covey</div>',
      "O que diferencia empatia de simpatia?",
      ["São a mesma coisa", "Empatia é sentir COM o outro; simpatia é sentir pena DO outro", "Simpatia é mais profunda", "Empatia é fingir que se importa"], 1,
      "Empatia envolve se colocar no lugar do outro. Simpatia é sentir pena à distância, sem realmente compreender."),

    L("Construindo Caráter", "Virtudes, integridade e a pessoa que você quer ser", 35,
      '<h3>O que é Caráter?</h3><p>Caráter é o conjunto de <strong>qualidades morais que definem quem você realmente é</strong> — não quando tudo vai bem, mas quando ninguém está olhando, quando é difícil fazer a coisa certa, quando há um preço a pagar pela integridade.</p><h3>Aristóteles e as Virtudes</h3><p>Para Aristóteles, virtude não é um sentimento — é um <strong>hábito</strong>. Você se torna corajoso praticando atos de coragem. Se torna honesto sendo honesto repetidamente. Virtude é o "justo meio" entre dois extremos:</p><p>• Coragem = meio entre covardia e imprudência<br>• Generosidade = meio entre avareza e desperdício<br>• Humildade = meio entre arrogância e autodepreciação</p><div class="highlight">🏋️ "Somos o que repetidamente fazemos. Excelência, então, não é um ato, mas um hábito." — Aristóteles. Caráter se constrói com escolhas diárias, não com grandes gestos ocasionais.</div><h3>Integridade na Prática</h3><p>Integridade é <strong>fazer o que é certo mesmo quando é difícil</strong>. É a cola que mantém todas as virtudes juntas.</p><div class="example">🎒 Cenário: você acha uma carteira com R$200 no chão do shopping. Ninguém viu. O que você faz? Sua resposta revela mais sobre seu caráter do que qualquer discurso sobre ética.</div><h3>Construindo Seu Caráter</h3><p><strong>1. Defina seus valores</strong> — O que é inegociável para você? Honestidade? Lealdade? Justiça?<br><strong>2. Pratique diariamente</strong> — Cada pequena decisão ética fortalece o músculo do caráter.<br><strong>3. Aceite o custo</strong> — Fazer a coisa certa às vezes tem preço. Esteja disposto a pagar.<br><strong>4. Tenha modelos</strong> — Quem você admira? O que admira neles? Cultive essas qualidades.</p><div class="thinker-quote">"O caráter de um homem é seu destino." — Heráclito</div><p>No fim, o que importa não é quanto dinheiro você ganhou ou quantos seguidores teve — é que tipo de pessoa você se tornou. Caráter é o legado mais duradouro que você pode construir.</p>',
      "Qual virtude Aristóteles considerava a mais importante para o caráter?",
      ["Inteligência", "Coragem (a moderação entre covardia e imprudência)", "Riqueza", "Popularidade"], 1,
      "Aristóteles via a coragem como virtude central — o equilíbrio entre covardia e imprudência.")
  ]
};

